code = """import json, pandas as pd, re

perfect = pd.DataFrame(var_call_CmOOFNkEE4FDRgexWx8zY4Yo)
perfect['purchase_id'] = perfect['purchase_id'].astype(str)

# load literature & fiction books
path_or_data = var_call_VKdjGbPNKKB2yPB0HyEIeFNw
if isinstance(path_or_data, str) and path_or_data.endswith('.json'):
    with open(path_or_data, 'r', encoding='utf-8') as f:
        books = json.load(f)
else:
    books = path_or_data
books_df = pd.DataFrame(books)

# English-language filter via details string
books_df['details'] = books_df['details'].astype(str)
books_df = books_df[books_df['details'].str.contains(r'\bEnglish\b', case=False, regex=True, na=False)].copy()

# fuzzy join: bookid_123 <-> purchaseid_123 via numeric suffix
num_re = re.compile(r'(\d+)')
books_df['num'] = books_df['book_id'].astype(str).str.extract(num_re)[0]
perfect['num'] = perfect['purchase_id'].astype(str).str.extract(num_re)[0]

merged = pd.merge(books_df, perfect[['purchase_id','avg_rating','num']], on='num', how='inner')
merged = merged.drop_duplicates(subset=['book_id']).copy()

# Prepare output
out = merged[['title','book_id','purchase_id']].copy()
# author names if JSON

def author_name(a):
    if a is None:
        return None
    if isinstance(a, str):
        s=a.strip()
        if s.startswith('{') and s.endswith('}'):
            try:
                j=json.loads(s)
                return j.get('name')
            except Exception:
                return a
        return a
    return str(a)

out['author'] = merged['author'].apply(author_name)
out['avg_rating'] = merged['avg_rating'].astype(float)

out = out.sort_values(['title','book_id']).to_dict(orient='records')

print('__RESULT__:')
print(json.dumps(out, ensure_ascii=False))"""

